- Implement `validation.ts` with helpers:
  ```ts
  const REQUIRED_FIELDS: (keyof StoryBrief)[] = [
    "video_goal",
    "target_audience",
    "company_or_brand_name",
    "tone_and_style",
    "desired_length",
    "video_type",
  ];

  interface ValidationErrors { [K in keyof StoryBrief]?: string }

  function validateRequiredFields(brief: StoryBrief): ValidationErrors {
    const errors: ValidationErrors = {};
    for (const field of REQUIRED_FIELDS) {
      const value = (brief as any)[field];
      if (value == null || value === "") {
        errors[field] = "This field is required.";
      }
    }
    return errors;
  }
  ```
- Wire this helper into `RequiredFieldsForm` (on primary action) via callbacks already planned, passing errors back into local form state.
